std::string convertMarkdownToHTML(std::string& markdown) {
    // Define markdown syntax patterns
    std::regex bold_pattern("(.*)\*\*(.*)\*\*(.*)");
    std::regex italic_pattern("(.*)\*(.*)\*(.*)");
    std::regex link_pattern("(.*)\[(.*)\]\((.*)\)(.*)");

    // Replace markdown syntax with HTML tags
    markdown = std::regex_replace(markdown, bold_pattern, "<strong>$2</strong>$3");
    markdown = std::regex_replace(markdown, italic_pattern, "<em>$2</em>$3");
    markdown = std::regex_replace(markdown, link_pattern, "<a href=\"$3\">$2</a>$4");

    return markdown;
}

int main() {
    std::string markdown = "This is **bold text**, and *italic text*. Here's a [link](https://example.com/).";
    std::string html = convertMarkdownToHTML(markdown);
    std::cout << "Markdown: " << markdown << "\nConverted to HTML: " << html << std::endl;
    return 0;
}
