function checkPrimes(array) {
  for (let i = 0; i < array.length; i++) {
    let num = array[i];
    if (num > 1) {
      for (let j = 2; j <= Math.sqrt(num); j++) {
        if (num % j === 0) {
          break;
        }
        if (j === Math.sqrt(num)) {
          console.log(`Prime number found: ${num}`);
          return;
        }
      }
    }
  }
}

// Example usage:
let numbers = [11, 12, 13, 17, 21];
checkPrimes(numbers);
